import axios from "axios";

const API_URL = "http://localhost:5000/api";

// Create axios instance with auth headers
const authAxios = axios.create({
  baseURL: API_URL,
});

// Add auth token to requests
authAxios.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem("token");
    if (token) {
      config.headers.Authorization = `Bearer ${token}`;
    }
    return config;
  },
  (error) => Promise.reject(error)
);

// Application APIs
export const fetchApplications = async () => {
  try {
    const response = await authAxios.get("/applications");
    return response.data;
  } catch (error) {
    console.error("Error fetching applications:", error);
    throw error;
  }
};

export const fetchApplicationById = async (id) => {
  try {
    const response = await authAxios.get(`/applications/${id}`);
    return response.data;
  } catch (error) {
    console.error(`Error fetching application ${id}:`, error);
    throw error;
  }
};

export const updateApplication = async (id, data) => {
  try {
    const response = await authAxios.patch(`/applications/${id}`, data);
    return response.data;
  } catch (error) {
    console.error(`Error updating application ${id}:`, error);
    throw error;
  }
};

// Contact APIs
export const fetchContacts = async () => {
    try {
        const response = await authAxios.get("/contact");
        return response.data;
    } catch (error) {
        console.error("Error fetching contacts:", error);
        throw error;
    }
};

export const fetchContactById = async (id) => {
    try {
        const response = await authAxios.get(`/contact/${id}`);
        return response.data;
    } catch (error) {
        console.error(`Error fetching contact ${id}:`, error);
        throw error;
    }
};

export const updateContactStatus = async (id, status) => {
    try {
        const response = await authAxios.patch(`/contact/${id}/status`, { status });
        return response.data;
    } catch (error) {
        console.error(`Error updating contact status ${id}:`, error);
        throw error;
    }
};

// Student APIs
export const fetchStudents = async () => {
    try {
        const response = await authAxios.get("/students");
        return response.data;
    } catch (error) {
        console.error("Error fetching students:", error);
        throw error;
    }
};

export const fetchStudent = async (id) => {
    try {
        const response = await authAxios.get(`/students/${id}`);
        return response.data;
    } catch (error) {
        console.error(`Error fetching student ${id}:`, error);
        throw error;
    }
};

// Course APIs
export const fetchCourses = async () => {
    try {
        const response = await authAxios.get("/courses");
        return response.data;
    } catch (error) {
        console.error("Error fetching courses:", error);
        throw error;
    }
};

export const fetchCourse = async (id) => {
    try {
        const response = await authAxios.get(`/courses/${id}`);
        return response.data;
    } catch (error) {
        console.error(`Error fetching course ${id}:`, error);
        throw error;
    }
};

// Dashboard Stats
export const fetchDashboardStats = async () => {
    try {
        const response = await authAxios.get("/dashboard/stats");
        return response.data;
    } catch (error) {
        console.error("Error fetching dashboard stats:", error);
        throw error;
    }
};
